const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const depthLimit = require('graphql-depth-limit');
const { GraphQLError } = require('graphql');

// Define your schema
const typeDefs = `#graphql
  type User {
    id: ID!
    name: String!
    posts: [Post!]!
    friends: [User!]!
  }

  type Post {
    id: ID!
    title: String!
    author: User!
    comments: [Comment!]!
  }

  type Comment {
    id: ID!
    text: String!
    author: User!
    post: Post!
  }

  type Query {
    user(id: ID!): User
    users: [User!]!
  }
`;

// Configure Apollo Server with depth limiting
const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [
    // Limit query depth to 7 levels
    depthLimit(
      7,
      { ignore: ['_service', '_entities'] }, // Ignore federation introspection
      (depths) => {
        // Custom error handler
        console.warn('Query depth exceeded:', depths);
        return new GraphQLError(
          `Query exceeds maximum depth of 7. Current depth: ${Math.max(...Object.values(depths))}`,
          {
            extensions: {
              code: 'QUERY_DEPTH_EXCEEDED',
              maxDepth: 7,
              actualDepth: Math.max(...Object.values(depths))
            }
          }
        );
      }
    )
  ],
  // Add additional security options
  introspection: process.env.NODE_ENV !== 'production', // Disable introspection in prod
  formatError: (formattedError, error) => {
    // Log security-related errors
    if (formattedError.extensions?.code === 'QUERY_DEPTH_EXCEEDED') {
      console.error('Security: Depth limit triggered', {
        timestamp: new Date().toISOString(),
        depth: formattedError.extensions.actualDepth
      });
    }
    return formattedError;
  }
});

// Start server
startStandaloneServer(server, {
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
  console.log('✓ Query depth limited to 7 levels');
});

const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const { createComplexityRule } = require('graphql-validation-complexity');
const { GraphQLError } = require('graphql');

// Define cost directives in schema
const typeDefs = `#graphql
  directive @cost(
    complexity: Int!
    multipliers: [String!]
    useMultipliers: Boolean
  ) on FIELD_DEFINITION

  type User {
    id: ID! @cost(complexity: 1)
    name: String! @cost(complexity: 1)
    email: String! @cost(complexity: 1)
    # Expensive field: loads all posts from database
    posts: [Post!]! @cost(complexity: 10, multipliers: ["first"], useMultipliers: true)
    # Very expensive: loads friends and their data
    friends: [User!]! @cost(complexity: 20, multipliers: ["first"], useMultipliers: true)
  }

  type Post {
    id: ID! @cost(complexity: 1)
    title: String! @cost(complexity: 1)
    content: String! @cost(complexity: 2)
    author: User! @cost(complexity: 5)
    # Expensive: loads comments with pagination
    comments(first: Int = 10): [Comment!]! @cost(complexity: 10, multipliers: ["first"], useMultipliers: true)
  }

  type Comment {
    id: ID! @cost(complexity: 1)
    text: String! @cost(complexity: 1)
    author: User! @cost(complexity: 5)
    post: Post! @cost(complexity: 5)
  }

  type Query {
    user(id: ID!): User @cost(complexity: 2)
    # Expensive query: loads multiple users
    users(first: Int = 10): [User!]! @cost(complexity: 5, multipliers: ["first"], useMultipliers: true)
    post(id: ID!): Post @cost(complexity: 2)
  }
`;

// Configure complexity analysis
const complexityLimit = 1000; // Maximum query cost

const server = new ApolloServer({
  typeDefs,
  resolvers,
  validationRules: [
    createComplexityRule({
      scalarCost: 1,          // Cost for scalar fields
      objectCost: 2,          // Base cost for object types
      listFactor: 10,         // Multiplier for list fields
      introspectionListFactor: 2,
      maximumComplexity: complexityLimit,
      onCost: (cost) => {
        console.log('Query complexity:', cost);
        if (cost > complexityLimit * 0.8) {
          console.warn('Query approaching complexity limit:', {
            cost,
            limit: complexityLimit,
            timestamp: new Date().toISOString()
          });
        }
      },
      createError: (cost, documentNode) => {
        return new GraphQLError(
          `Query exceeds complexity limit of ${complexityLimit}. Current complexity: ${cost}`,
          {
            extensions: {
              code: 'QUERY_COMPLEXITY_EXCEEDED',
              maxComplexity: complexityLimit,
              actualComplexity: cost,
              recommendation: 'Reduce query depth, remove unnecessary fields, or use pagination'
            }
          }
        );
      }
    })
  ]
});

startStandaloneServer(server, {
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
  console.log(`✓ Query complexity limited to ${complexityLimit}`);
});

const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const Redis = require('ioredis');
const { GraphQLError } = require('graphql');
const { getComplexity, simpleEstimator, fieldExtensionsEstimator } = require('graphql-query-complexity');

// Initialize Redis for distributed rate limiting
const redis = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD
});

// Token bucket configuration
const BUCKET_CONFIG = {
  MAX_TOKENS: 5000,           // Maximum cost budget per window
  REFILL_RATE: 100,           // Tokens added per second
  REFILL_INTERVAL: 1000,      // Refill every 1 second
  WINDOW_SIZE: 60             // 60 second sliding window
};

// Token bucket implementation
class TokenBucket {
  constructor(identifier) {
    this.identifier = identifier;
    this.key = `rate_limit:${identifier}`;
  }

  async consume(cost) {
    const now = Date.now();
    const script = `
      local key = KEYS[1]
      local max_tokens = tonumber(ARGV[1])
      local refill_rate = tonumber(ARGV[2])
      local cost = tonumber(ARGV[3])
      local now = tonumber(ARGV[4])

      local bucket = redis.call('HMGET', key, 'tokens', 'last_refill')
      local tokens = tonumber(bucket[1]) or max_tokens
      local last_refill = tonumber(bucket[2]) or now

      -- Calculate token refill
      local time_passed = (now - last_refill) / 1000
      local refill_amount = math.floor(time_passed * refill_rate)
      tokens = math.min(max_tokens, tokens + refill_amount)

      -- Check if enough tokens
      if tokens >= cost then
        tokens = tokens - cost
        redis.call('HMSET', key, 'tokens', tokens, 'last_refill', now)
        redis.call('EXPIRE', key, 120)
        return {1, tokens}
      else
        return {0, tokens}
      end
    `;

    const result = await redis.eval(
      script,
      1,
      this.key,
      BUCKET_CONFIG.MAX_TOKENS,
      BUCKET_CONFIG.REFILL_RATE,
      cost,
      now
    );

    return {
      allowed: result[0] === 1,
      remainingTokens: result[1],
      retryAfter: result[0] === 0 ? Math.ceil((cost - result[1]) / BUCKET_CONFIG.REFILL_RATE) : 0
    };
  }
}

// Custom plugin for query cost and rate limiting
const queryCostPlugin = {
  async requestDidStart() {
    return {
      async didResolveOperation(requestContext) {
        const { schema, document, operationName, contextValue } = requestContext;

        // Get user identifier (IP or user ID)
        const identifier = contextValue.userId || contextValue.req.ip || 'anonymous';

        // Calculate query complexity
        const complexity = getComplexity({
          schema,
          operationName,
          query: document,
          variables: requestContext.request.variables,
          estimators: [
            fieldExtensionsEstimator(),
            simpleEstimator({ defaultComplexity: 1 })
          ]
        });

        // Apply rate limiting based on complexity
        const bucket = new TokenBucket(identifier);
        const result = await bucket.consume(complexity);

        if (!result.allowed) {
          throw new GraphQLError(
            `Query cost exceeds available budget. Try again in ${result.retryAfter} seconds.`,
            {
              extensions: {
                code: 'RATE_LIMIT_EXCEEDED',
                queryCost: complexity,
                remainingBudget: result.remainingTokens,
                retryAfter: result.retryAfter,
                maxBudget: BUCKET_CONFIG.MAX_TOKENS,
                refillRate: BUCKET_CONFIG.REFILL_RATE
              }
            }
          );
        }

        // Log query cost for monitoring
        console.log('Query cost analysis:', {
          identifier,
          complexity,
          remainingTokens: result.remainingTokens,
          timestamp: new Date().toISOString()
        });

        // Add cost info to response headers
        requestContext.response.http.headers.set('X-Query-Cost', complexity.toString());
        requestContext.response.http.headers.set('X-Rate-Limit-Remaining', result.remainingTokens.toString());
      }
    };
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  plugins: [queryCostPlugin]
});

startStandaloneServer(server, {
  context: async ({ req }) => {
    // Extract user from JWT or use IP
