    const userId = token ? verifyJWT(token).userId : null;
    return { req, userId };
  },
  listen: { port: 4000 }
}).then(({ url }) => {
  console.log(`🚀 Server ready at ${url}`);
  console.log('✓ Query cost analysis with token bucket rate limiting enabled');
});
